def min_removes_to_make_valid_parentheses(s: str) -> int:
    open_count = 0
    removals = 0

    for char in s:
        if char == '(':
            open_count += 1
        elif char == ')':
            if open_count > 0:
                open_count -= 1
            else:
                removals += 1

    removals += open_count
    return removals
